INSERT INTO blog_posts (slug, title, excerpt, content, cover_image, category, read_time_minutes, tags, published_at) VALUES
('kak-vybrat-moshchnost-generatora', 'Как правильно рассчитать мощность генератора для дома',
 'Разбираем, как учитывать пусковые токи бытовых приборов и не ошибиться с запасом мощности при выборе генератора.',
 'При выборе генератора важно учитывать не только суммарную мощность приборов, которые вы планируете подключить, но и пусковые токи — они могут превышать номинальную мощность в 2-3 раза для холодильников, насосов и другого оборудования с электродвигателем. Рекомендуем закладывать запас не менее 20-30% от расчётной нагрузки. В нашем калькуляторе на главной странице вы можете быстро подобрать подходящую модель, отметив используемые приборы.',
 'https://images.pexels.com/photos/7359566/pexels-photo-7359566.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200',
 'Советы', 6, '["мощность","выбор","калькулятор"]', now() - interval '10 days'),
('dizel-ili-benzin', 'Дизельный или бензиновый генератор: что выбрать',
 'Сравниваем два самых популярных типа генераторов по стоимости владения, ресурсу и удобству эксплуатации.',
 'Бензиновые генераторы дешевле в покупке и легче по весу, что делает их удобными для периодического использования. Дизельные генераторы дороже, но экономичнее в пересчёте на моточас и имеют больший ресурс — от 10 000 моточасов против 1 500-3 000 у бензиновых аналогов. Если генератор нужен для частого или постоянного использования (ферма, стройка, магазин), дизельный вариант окупится быстрее.',
 'https://images.pexels.com/photos/29491360/pexels-photo-29491360.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200',
 'Обзоры', 8, '["дизель","бензин","сравнение"]', now() - interval '20 days'),
('avr-avtomaticheskiy-vvod-rezerva', 'Что такое АВР и нужен ли он вам',
 'Объясняем принцип работы блока автоматического ввода резерва и когда стоит доплатить за эту опцию.',
 'АВР (автоматический ввод резерва) — это блок автоматики, который отслеживает наличие напряжения в сети и при его пропадании самостоятельно запускает генератор и переключает нагрузку на него в течение нескольких секунд. Это особенно актуально для владельцев систем видеонаблюдения, серверов, холодильного оборудования и медицинской техники, где важна бесперебойность питания. Без АВР переключение придётся выполнять вручную.',
 'https://images.pexels.com/photos/164391/pexels-photo-164391.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200',
 'Технологии', 5, '["авр","автоматика"]', now() - interval '30 days'),
('obsluzhivanie-generatora-zimoy', 'Как подготовить генератор к зиме',
 'Пошаговая инструкция по консервации и обслуживанию генератора перед наступлением холодов.',
 'Перед зимним хранением слейте остатки топлива или используйте стабилизатор, замените масло, проверьте свечи зажигания и воздушный фильтр. Храните генератор в сухом помещении при плюсовой температуре. Перед первым запуском после зимы обязательно проверьте уровень масла и топлива, а также состояние проводки и разъёмов.',
 'https://images.pexels.com/photos/7285965/pexels-photo-7285965.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200',
 'Обслуживание', 7, '["обслуживание","зима"]', now() - interval '5 days');

INSERT INTO diagnostic_symptoms (title, description, steps, sort_order) VALUES
('Генератор не заводится', 'Двигатель не запускается или глохнет сразу после запуска.',
 '["Проверьте уровень топлива и масла — большинство моделей блокируют запуск при низком уровне масла.","Убедитесь, что топливный кран открыт, а рычаг подсоса (воздушной заслонки) установлен в положение запуска холодного двигателя.","Проверьте состояние свечи зажигания — очистите или замените при необходимости.","Проверьте, не сработал ли автоматический выключатель перегрузки на панели.","Если генератор не заводился более 3 месяцев, слейте старое топливо и залейте свежее."]', 1),
('Нет напряжения в розетке', 'Генератор работает, но на выходе отсутствует напряжение 220В.',
 '["Проверьте, не сработал ли автоматический выключатель (автомат защиты) на панели генератора — включите его повторно.","Убедитесь, что используемый удлинитель и вилка исправны — проверьте на другом приборе.","Для генераторов с AVR (регулятором напряжения) проверьте исправность блока возбуждения.","Проверьте обороты двигателя — заниженные обороты могут не создавать номинальное напряжение.","Если проблема сохраняется, обратитесь в сервисный центр для диагностики обмоток генератора."]', 2),
('Двигатель работает неровно', 'Генератор запускается, но двигатель троит, глохнет под нагрузкой или плавают обороты.',
 '["Проверьте и при необходимости замените воздушный и топливный фильтры.","Проверьте зазор и состояние свечи зажигания.","Убедитесь, что топливо свежее и не содержит воды или конденсата.","Проверьте настройку карбюратора — при необходимости выполните регулировку в сервисе.","Снизьте подключенную нагрузку — возможно, она превышает номинальную мощность генератора."]', 3);
